import { constants } from "node:fs";
import { access, readFile, writeFile } from "node:fs/promises";

export async function pathExists(path: string): Promise<boolean> {
  try {
    await access(path);
    return true;
  } catch {
    return false;
  }
}

export async function readTextFile(path: string): Promise<string> {
  return readFile(path, "utf8");
}

export async function pathReadable(path: string): Promise<boolean> {
  try {
    await access(path, constants.R_OK);
    return true;
  } catch {
    return false;
  }
}

export async function writeTextFile(path: string, content: string): Promise<void> {
  await writeFile(path, content, "utf8");
}

import { relative, resolve } from "node:path";

import { loadConfig } from "c12";
import { z } from "zod";

export const RUN_CONFIG_FILE_NAME = "impl-run.config.json";

export const reasoningEffortSchema = z.enum(["low", "medium", "high", "xhigh"]);
export const primaryHarnessSchema = z.literal("claude-code");
export const secondaryHarnessSchema = z.enum(["codex", "copilot", "none"]);

export const roleAssignmentSchema = z.object({
  secondary_harness: secondaryHarnessSchema,
  model: z.string().min(1),
  reasoning_effort: reasoningEffortSchema,
});

export const epicVerifierAssignmentSchema = roleAssignmentSchema.extend({
  label: z.string().min(1),
});

export const implRunConfigSchema = z
  .object({
    version: z.literal(1),
    primary_harness: primaryHarnessSchema,
    story_implementor: roleAssignmentSchema,
    quick_fixer: roleAssignmentSchema,
    story_verifier_1: roleAssignmentSchema,
    story_verifier_2: roleAssignmentSchema,
    self_review: z.object({
      passes: z.number().int().min(1).max(5),
    }),
    epic_verifiers: z.array(epicVerifierAssignmentSchema).min(1),
    epic_synthesizer: roleAssignmentSchema,
  })
  .superRefine((value, ctx) => {
    if (value.story_implementor.secondary_harness === "copilot") {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message:
          "story_implementor.secondary_harness cannot be copilot in v1",
        path: ["story_implementor", "secondary_harness"],
      });
    }

    const seenLabels = new Set<string>();
    for (const [index, verifier] of value.epic_verifiers.entries()) {
      if (seenLabels.has(verifier.label)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: "Duplicate epic verifier label",
          path: ["epic_verifiers", index, "label"],
        });
      }
      seenLabels.add(verifier.label);
    }
  });

export type ReasoningEffort = z.infer<typeof reasoningEffortSchema>;
export type PrimaryHarness = z.infer<typeof primaryHarnessSchema>;
export type SecondaryHarness = z.infer<typeof secondaryHarnessSchema>;
export type RoleAssignment = z.infer<typeof roleAssignmentSchema>;
export type EpicVerifierAssignment = z.infer<typeof epicVerifierAssignmentSchema>;
export type ImplRunConfig = z.infer<typeof implRunConfigSchema>;

export function resolveRunConfigPath(
  specPackRoot: string,
  configPath?: string
): string {
  if (!configPath) {
    return resolve(specPackRoot, RUN_CONFIG_FILE_NAME);
  }

  return resolve(specPackRoot, configPath);
}

export async function loadRunConfig(input: {
  specPackRoot: string;
  configPath?: string;
}): Promise<ImplRunConfig> {
  const resolvedPath = resolveRunConfigPath(input.specPackRoot, input.configPath);
  const { config } = await loadConfig({
    cwd: resolve(input.specPackRoot),
    configFile: relative(resolve(input.specPackRoot), resolvedPath),
    configFileRequired: true,
    rcFile: false,
    globalRc: false,
    packageJson: false,
    dotenv: false,
    extend: false,
  });

  return implRunConfigSchema.parse(config);
}

import { createHash } from "node:crypto";
import { mkdir } from "node:fs/promises";
import { dirname, join, relative, resolve } from "node:path";

import { Glob } from "bun";

const ROOT = resolve(import.meta.dir, "..");
const BASELINE_PATH = join(
  ROOT,
  ".test-tmp",
  "green-verify",
  "test-file-baseline.json"
);

interface BaselineEntry {
  path: string;
  sha256: string;
}

async function collectTestBaseline(): Promise<BaselineEntry[]> {
  const glob = new Glob("**/*.test.ts");
  const entries: BaselineEntry[] = [];

  for await (const match of glob.scan({
    cwd: ROOT,
    absolute: true,
    onlyFiles: true,
  })) {
    if (
      match.includes("/node_modules/") ||
      match.includes("/dist/") ||
      match.includes("/.test-tmp/")
    ) {
      continue;
    }

    const content = await Bun.file(match).text();
    entries.push({
      path: relative(ROOT, match),
      sha256: createHash("sha256").update(content).digest("hex"),
    });
  }

  return entries.sort((left, right) => left.path.localeCompare(right.path));
}

async function main() {
  const force = process.argv.includes("--force");
  const baselineFile = Bun.file(BASELINE_PATH);

  if (!force && (await baselineFile.exists())) {
    console.log(`Test baseline already exists at ${BASELINE_PATH}`);
    return;
  }

  const baseline = collectTestBaseline();
  await mkdir(dirname(BASELINE_PATH), { recursive: true });
  await Bun.write(
    BASELINE_PATH,
    `${JSON.stringify(await baseline, null, 2)}\n`
  );
  console.log(`Captured test baseline at ${BASELINE_PATH}`);
}

main().catch((error: unknown) => {
  console.error(
    error instanceof Error ? error.message : String(error)
  );
  process.exit(1);
});

import { createHash } from "node:crypto";
import { join, relative, resolve } from "node:path";

import { Glob } from "bun";

const ROOT = resolve(import.meta.dir, "..");
const BASELINE_PATH = join(
  ROOT,
  ".test-tmp",
  "green-verify",
  "test-file-baseline.json"
);

interface BaselineEntry {
  path: string;
  sha256: string;
}

async function collectCurrentEntries(): Promise<BaselineEntry[]> {
  const glob = new Glob("**/*.test.ts");
  const entries: BaselineEntry[] = [];

  for await (const match of glob.scan({
    cwd: ROOT,
    absolute: true,
    onlyFiles: true,
  })) {
    if (
      match.includes("/node_modules/") ||
      match.includes("/dist/") ||
      match.includes("/.test-tmp/")
    ) {
      continue;
    }

    const content = await Bun.file(match).text();
    entries.push({
      path: relative(ROOT, match),
      sha256: createHash("sha256").update(content).digest("hex"),
    });
  }

  return entries.sort((left, right) => left.path.localeCompare(right.path));
}

async function main() {
  const baselineFile = Bun.file(BASELINE_PATH);
  if (!(await baselineFile.exists())) {
    console.error(
      `Missing test baseline at ${BASELINE_PATH}. Run bun run capture:test-baseline after the red phase.`
    );
    process.exit(1);
  }

  const baseline = (await baselineFile.json()) as BaselineEntry[];
  const current = await collectCurrentEntries();
  const baselineMap = new Map(baseline.map((entry) => [entry.path, entry.sha256]));
  const currentMap = new Map(current.map((entry) => [entry.path, entry.sha256]));
  const changedPaths = new Set<string>();

  for (const [path, sha256] of currentMap) {
    if (baselineMap.get(path) !== sha256) {
      changedPaths.add(path);
    }
  }

  for (const path of baselineMap.keys()) {
    if (!currentMap.has(path)) {
      changedPaths.add(path);
    }
  }

  if (changedPaths.size > 0) {
    console.error("Test files changed after the captured red-phase baseline:");
    for (const path of [...changedPaths].sort((left, right) =>
      left.localeCompare(right)
    )) {
      console.error(`- ${path}`);
    }
    process.exit(1);
  }

  console.log("No test file changes detected since the captured baseline.");
}

main().catch((error: unknown) => {
  console.error(
    error instanceof Error ? error.message : String(error)
  );
  process.exit(1);
});

import { chmod, mkdir, mkdtemp, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join, relative } from "node:path";
import { describe, expect, test } from "bun:test";

import {
  ROOT,
  createSpecPack,
  parseJsonOutput,
  runSourceCli,
  writeTextFile,
} from "./test-helpers";

async function createExternalSpecPack(): Promise<string> {
  const specPackRoot = await mkdtemp(join(tmpdir(), "impl-cli-outside-git-"));
  await mkdir(join(specPackRoot, "stories"), { recursive: true });
  await writeFile(join(specPackRoot, "epic.md"), "# Epic\n", "utf8");
  await writeFile(
    join(specPackRoot, "tech-design.md"),
    "# Technical Design\n",
    "utf8"
  );
  await writeFile(join(specPackRoot, "test-plan.md"), "# Test Plan\n", "utf8");
  await writeFile(
    join(specPackRoot, "stories", "00-foundation.md"),
    "# Story 0: Foundation\n",
    "utf8"
  );
  return specPackRoot;
}

describe("security guardrails", () => {
  test("resolves spec-pack roots to absolute paths", async () => {
    const specPackRoot = await createSpecPack("security-absolute-root");
    const relativeSpecPackRoot = relative(ROOT, specPackRoot);
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      relativeSpecPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(0);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.result.specPackRoot).toBe(specPackRoot);
  });

  test("rejects spec-pack roots outside a git repo", async () => {
    const specPackRoot = await createExternalSpecPack();
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(3);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.status).toBe("blocked");
    expect(envelope.errors[0].code).toBe("INVALID_SPEC_PACK");
    expect(envelope.result.blockers).toContain(
      `Spec-pack root is not inside a git repo: ${specPackRoot}`
    );
  });

  test("rejects unreadable prompt inserts with PROMPT_INSERT_INVALID", async () => {
    const specPackRoot = await createSpecPack("security-unreadable-insert");
    const insertPath = join(
      specPackRoot,
      "custom-story-impl-prompt-insert.md"
    );
    await writeTextFile(insertPath, "Custom implementor insert\n");
    await chmod(insertPath, 0o000);

    try {
      const run = await runSourceCli([
        "inspect",
        "--spec-pack-root",
        specPackRoot,
        "--json",
      ]);

      expect(run.exitCode).toBe(3);

      const envelope = parseJsonOutput<any>(run.stdout);
      expect(envelope.status).toBe("blocked");
      expect(envelope.errors[0].code).toBe("PROMPT_INSERT_INVALID");
      expect(envelope.result.blockers).toContain(
        "Unreadable prompt insert: custom-story-impl-prompt-insert.md"
      );
    } finally {
      await chmod(insertPath, 0o644);
    }
  });

  test("returns needs-user-decision instead of guessing when gate discovery is ambiguous", async () => {
    const specPackRoot = await createSpecPack("security-ambiguous-gates");
    await writeTextFile(
      join(specPackRoot, "impl-run.config.json"),
      JSON.stringify(
        {
          version: 1,
          primary_harness: "claude-code",
          story_implementor: {
            secondary_harness: "none",
            model: "claude-sonnet",
            reasoning_effort: "high",
          },
          quick_fixer: {
            secondary_harness: "none",
            model: "claude-sonnet",
            reasoning_effort: "medium",
          },
          story_verifier_1: {
            secondary_harness: "none",
            model: "claude-sonnet",
            reasoning_effort: "high",
          },
          story_verifier_2: {
            secondary_harness: "none",
            model: "claude-sonnet",
            reasoning_effort: "high",
          },
          self_review: {
            passes: 2,
          },
          epic_verifiers: [
            {
              label: "epic-verifier-1",
              secondary_harness: "none",
              model: "claude-sonnet",
              reasoning_effort: "high",
            },
          ],
          epic_synthesizer: {
            secondary_harness: "none",
            model: "claude-sonnet",
            reasoning_effort: "high",
          },
        },
        null,
        2
      )
    );
    await writeTextFile(
      join(specPackRoot, "README.md"),
      [
        "# Verification",
        "",
        "Story Gate: bun run story-check-a",
        "Story Gate: bun run story-check-b",
        "Epic Gate: bun run epic-check-a",
        "",
      ].join("\n")
    );

    const providerBinDir = await mkdtemp(join(tmpdir(), "impl-cli-provider-bin-"));
    const claudePath = join(providerBinDir, "claude");
    await writeFile(
      claudePath,
      [
        "#!/bin/sh",
        'if [ "$1" = "--version" ]; then',
        '  echo "claude 1.0.0"',
        "  exit 0",
        "fi",
        'if [ "$1" = "auth" ] && [ "$2" = "status" ]; then',
        '  echo "authenticated"',
        "  exit 0",
        "fi",
        "exit 1",
        "",
      ].join("\n"),
      "utf8"
    );
    await chmod(claudePath, 0o755);

    const run = await runSourceCli(
      ["preflight", "--spec-pack-root", specPackRoot, "--json"],
      {
        env: {
          PATH: `${providerBinDir}:${process.env.PATH ?? ""}`,
        },
      }
    );

    expect(run.exitCode).toBe(2);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.status).toBe("needs-user-decision");
    expect(envelope.errors).toContainEqual(
      expect.objectContaining({
        code: "VERIFICATION_GATE_UNRESOLVED",
      })
    );
  });
});
